async (params, browser) => {
  // Open post page
  await browser.open(`${params.post_url}`)

  // Wait for post to load
  await browser.waitForSelector('h1, [class*=\'post-title\'], article', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to comments section
  await browser.scroll({ direction: 'down', amount: 5000 })

  await browser.wait(2000)

  // Scroll to load more comments
  await browser.scroll({ direction: 'down', amount: 3000 })

  await browser.wait(2000)

  // Extract comments
  const comments_data = await browser.evaluate(`const comments = []; const commentEls = document.querySelectorAll('[class*="comment"], [class*="Comment"], [data-testid="comment"]'); for (let i = 0; i < Math.min(commentEls.length, 20); i++) { const el = commentEls[i]; const authorEl = el.querySelector('[class*="author"] a, [class*="name"] a, [class*="commenter"]'); const contentEl = el.querySelector('[class*="body"] p, [class*="content"] p, [class*="text"]'); const dateEl = el.querySelector('time, [class*="date"], [class*="timestamp"]'); const likesEl = el.querySelector('[class*="like"] span, [class*="heart"] span, [class*="reaction"]'); if (contentEl && contentEl.textContent.trim().length > 0) { comments.push({ author: authorEl ? authorEl.textContent.trim() : 'Anonymous', content: contentEl ? contentEl.textContent.trim().substring(0, 500) : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', likes: likesEl ? likesEl.textContent.trim() : '' }); } } const totalEl = document.querySelector('[class*="comment-count"], [class*="response-count"]'); return { total_comments: totalEl ? totalEl.textContent.trim() : '', scraped_count: comments.length, comments: comments, url: window.location.href }`)

  return comments_data
}
